(window.webpackJsonp=window.webpackJsonp||[]).push([[27],{1306:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">nums</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> findLengthOfLCIS = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">nums</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> maxLen=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">let</span> tempLen=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;nums.length;i++){\\n    <span class=\\"hljs-keyword\\">if</span>(i===<span class=\\"hljs-number\\">0</span> || nums[i]&gt;nums[i<span class=\\"hljs-number\\">-1</span>])tempLen++\\n    <span class=\\"hljs-keyword\\">else</span>{\\n      maxLen=<span class=\\"hljs-built_in\\">Math</span>.max(maxLen,tempLen)\\n      tempLen=<span class=\\"hljs-number\\">1</span>\\n    }\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-built_in\\">Math</span>.max(maxLen,tempLen)\\n};\\n</code></pre>\\n"],"titleSlug":"longest-continuous-increasing-subsequence","hasThinking":false,"content":"<p>\u7ed9\u5b9a\u4e00\u4e2a\u672a\u7ecf\u6392\u5e8f\u7684\u6574\u6570\u6570\u7ec4\uff0c\u627e\u5230\u6700\u957f\u4e14<strong> \u8fde\u7eed\u9012\u589e\u7684\u5b50\u5e8f\u5217</strong>\uff0c\u5e76\u8fd4\u56de\u8be5\u5e8f\u5217\u7684\u957f\u5ea6\u3002</p>\\n\\n<p><strong>\u8fde\u7eed\u9012\u589e\u7684\u5b50\u5e8f\u5217</strong> \u53ef\u4ee5\u7531\u4e24\u4e2a\u4e0b\u6807 <code>l</code> \u548c <code>r</code>\uff08<code>l < r</code>\uff09\u786e\u5b9a\uff0c\u5982\u679c\u5bf9\u4e8e\u6bcf\u4e2a <code>l <= i < r</code>\uff0c\u90fd\u6709 <code>nums[i] < nums[i + 1]</code> \uff0c\u90a3\u4e48\u5b50\u5e8f\u5217 <code>[nums[l], nums[l + 1], ..., nums[r - 1], nums[r]]</code> \u5c31\u662f\u8fde\u7eed\u9012\u589e\u5b50\u5e8f\u5217\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>nums = [1,3,5,4,7]\\n<strong>\u8f93\u51fa\uff1a</strong>3\\n<strong>\u89e3\u91ca\uff1a</strong>\u6700\u957f\u8fde\u7eed\u9012\u589e\u5e8f\u5217\u662f [1,3,5], \u957f\u5ea6\u4e3a3\u3002\\n\u5c3d\u7ba1 [1,3,5,7] \u4e5f\u662f\u5347\u5e8f\u7684\u5b50\u5e8f\u5217, \u4f46\u5b83\u4e0d\u662f\u8fde\u7eed\u7684\uff0c\u56e0\u4e3a 5 \u548c 7 \u5728\u539f\u6570\u7ec4\u91cc\u88ab 4 \u9694\u5f00\u3002 \\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>nums = [2,2,2,2,2]\\n<strong>\u8f93\u51fa\uff1a</strong>1\\n<strong>\u89e3\u91ca\uff1a</strong>\u6700\u957f\u8fde\u7eed\u9012\u589e\u5e8f\u5217\u662f [2], \u957f\u5ea6\u4e3a1\u3002\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 <= nums.length <= 10<sup>4</sup></code></li>\\n\\t<li><code>-10<sup>9</sup> <= nums[i] <= 10<sup>9</sup></code></li>\\n</ul>\\n","title":"674. \u6700\u957f\u8fde\u7eed\u9012\u589e\u5e8f\u5217","relatedTags":["\u6570\u7ec4"],"difficult":"Easy","lang":["javascript"],"uniqueID":"674"}')}}]);